+
+function compareVersion(currentVersion: number, operator: string, expectedVersion: number): boolean {
+  switch (operator) {
+    case ">":
+      return currentVersion > expectedVersion;
+    case ">=":
+      return currentVersion >= expectedVersion;
+    case "<":
+      return currentVersion < expectedVersion;
+    case "<=":
+      return currentVersion <= expectedVersion;
+    case "==":
+    case "=":
+      return currentVersion === expectedVersion;
+    default:
+      return false;
+  }
